import React from 'react';
import SongCard from './SongCard';

const SimilarSongsModal = ({
  similarSongs,
  selectedBaseSong,
  currentSongId,
  isPlaying,
  onClose,
  onPlay,
  onSave
}) => {
  const defaultArtwork = 'https://via.placeholder.com/1200x1200/0f172a/e2e8f0?text=Music';


  if (!similarSongs || similarSongs.length === 0) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="similar-songs-modal glass-panel" onClick={(e) => e.stopPropagation()}>
        <div className="similar-songs-modal__header">
          <div>
            <span className="eyebrow">Song Similarity</span>
            <h3>Similar to "{selectedBaseSong?.title}" by {selectedBaseSong?.artist}</h3>
          </div>
          <button
            type="button"
            className="btn btn-ghost btn-small modal-close"
            onClick={onClose}
            aria-label="Close similar songs modal"
            style={{position: 'absolute', top: '1rem', right: '1.5rem'}}
          >
            ✕
          </button>
        </div>

        <div className="similar-songs-grid">
          {similarSongs.map((song, index) => (
            <SongCard
              key={`similar-${index}`}
              song={song}
              index={`similar-${index}`}
              currentSongId={currentSongId}
              isPlaying={isPlaying}
              onPlay={onPlay}
              onSimilar={() => {}} // Disabled in modal
              onSave={onSave}
              similarSongsLoading={false}
              selectedBaseSong={null}
            />
          ))}
        </div>

        <div className="modal-actions">
          <button 
            className="btn btn-secondary" 
            onClick={onClose}
            style={{marginRight: '1rem'}}
          >
            Cancel
          </button>
          <button 
            className="btn btn-primary"
            onClick={onClose}
          >
            Done
          </button>
        </div>
      </div>
    </div>
  );


  return (
    <div className="modal-overlay" onClick={onClose}>
        <div className="similar-songs-modal glass-panel" onClick={(e) => e.stopPropagation()}>
          <div className="similar-songs-modal__header">
            <div>
              <span className="eyebrow">Song Similarity</span>
              <h3>Similar to "{selectedBaseSong?.title}" by {selectedBaseSong?.artist}</h3>
            </div>
            <button
              type="button"
              className="btn btn-ghost btn-small modal-close"
              onClick={onClose}
              aria-label="Close similar songs modal"
            >
              ✕
            </button>
          </div>

          <div className="similar-songs-grid">
            {similarSongs.map((song, index) => (
              <SongCard
                key={`similar-${index}`}
                song={song}
                index={`similar-${index}`}
                currentSongId={currentSongId}
                isPlaying={isPlaying}
                onPlay={onPlay}
                onSimilar={() => {}} // Disabled in modal
                onSave={onSave}
                similarSongsLoading={false}
                selectedBaseSong={null}
              />
            ))}
          </div>

          <div className="modal-actions">
            <button 
              className="btn btn-secondary" 
              onClick={onClose}
              style={{marginRight: '1rem'}}
            >
              Cancel
            </button>
            <button 
              className="btn btn-primary"
              onClick={onClose}
            >
              Done
            </button>
          </div>
        </div>

    </div>
  );
};

export default SimilarSongsModal;
